/**
 * ローカルセッションを起動するために必要なパラメータの定義
 */
export interface StartLocalSessionParameters {
	/**
	 * セッションを動作させるためのアプリケーション情報。
	 * 本値は、それぞれ以下のような挙動を期待される。
	 * 1. 本値が入っていない場合、sessionIdからセッション情報を引いて、アプリケーション情報を特定することが期待される
	 * 2. 本値にURLが入っている場合、そのURLで指定されるアプリケーションの読み込みが期待される
	 * 3. 本値にtypeとversionが入っている場合、その情報を基にメッセージ受信側がURLを構築してアプリケーションを読み込む事が期待される
	 */
	application: ApplicationIdentifier;

	/**
	 * セッションを動作させるための追加アプリケーション情報。
	 * 期待される動作はapplicationと同様だが、カスケードすることが想定される。
	 */
	cascadeApplications?: ApplicationIdentifier[];

	/**
	 * 本メッセージを遅延させる範囲をミリ秒で指定する。
	 * 本値が設定されていた場合、 `Math.random() * delayRange` 分の処理遅延を起こした上で、本メッセージを処理することが期待される
	 */
	delayRange?: number;

	/**
	 * ローカルセッションに引き渡すスタートメッセージ。
	 * 指定されない場合、COESessionStartMessageを引き渡さずに起動する。
	 */
	message?: COESessionStartMessage<any>;

	/**
	 * ローカルセッションからのメッセージを処理するハンドラ。
	 * 本ハンドラを指定して起動した場合、子セッションが送信したCOEExternalMessageは、本ハンドラに届けられる。
	 */
	messageHandler?: (message: COEExternalMessage | COEEndMessage) => void;

	/**
	 * サービス・アプリケーションで利用するための任意の追加データ。
	 */
	additionalData?: any;

	/**
	 * application, cascadeApplications等の情報を総合し、コンテンツのどういったサイズで起動することを期待しているかという値。
	 * 省略された場合、そのプラットフォームにおけるデフォルト値として解釈される事を期待する。
	 */
	size?: COEContentSize;

	/**
	 * ローカルセッションに与えるplaylog情報。
	 * 対象のセッションはこの情報をもとにリプレイさせることが期待される。
	 * 本値は COEExitSessionParameters#needsPlaylog によって取得されるものと同一の形式でなければならない。
	 * (本値の具体的な型についてはサービス側に委ねられる。)
	 */
	playlog?: any;
}

import type { COEExitSessionParameters, COEPlugin, COEStartSessionParameters } from "@akashic-environment/coe-plugin";
import type { COEExternalMessage, SessionId } from "@akashic-extension/coe-messages";
import { getSessionId, TrustedPlayerId } from "./global";
import type { StartLocalSessionParameters } from "./parameters";

let localSessionCount: number = 0;

/**
 * ローカルセッションを起動する。
 *
 * @param params ローカルセッションの起動パラメータ
 */
export function startLocalSession(params: StartLocalSessionParameters): SessionId {
	// ローカルセッションの起動
	const localSessionId = `${getSessionId()}-${localSessionCount++}`;
	const coeParams: COEStartSessionParameters = {
		sessionId: localSessionId,
		local: true,
		application: params.application,
		cascadeApplications: params.cascadeApplications,
		delayRange: params.delayRange,
		additionalData: params.additionalData,
		size: params.size,
		playlog: params.playlog,
		messageHandler: params.messageHandler as (m: COEExternalMessage) => void
	};

	if (params.message) {
		coeParams.localEvents = [[32, 0, TrustedPlayerId, params.message]];
	}

	startSession(coeParams);

	return localSessionId;
}

/**
 * coe-plugin 経由で共体験セッションを開始する。
 * @param parameters 開始する共体験セッションの起動情報
 */
export function startSession(parameters: COEStartSessionParameters): void {
	if (g.game.external.coe && g.game.external.coe.startSession) {
		(g.game.external.coe as COEPlugin).startSession(parameters);
	}
}

/**
 * coe-plugin 経由で共体験セッションのUI表示を終了する。
 * @param sessionId その共体験セッションを一意に識別するためのID
 * @param parameters UI表示を終了に伴う追加処理を格納する情報
 */
export function exitSession(sessionId: SessionId, parameters?: COEExitSessionParameters): void {
	if (g.game.external.coe && g.game.external.coe.exitSession) {
		(g.game.external.coe as COEPlugin).exitSession(sessionId, parameters);
	}
}

/**
 * 本共体験セッションを終了する。
 *
 * @param result 本共体験セッションの結果。
 *   このメソッド呼び出し後、 send プラグイン経由で本値を含めた終了メッセージがシステム側に通知される。
 *   本値が null または undefined である場合、結果はなかったものとして取り扱われる。
 */
export function exit(result?: any): void {
	const sessionId = getSessionId();
	if (g.game.external.send) {
		if (result != null) {
			g.game.external.send({
				type: "end",
				sessionId,
				data: {
					result
				}
			} as COEExternalMessage);
		} else {
			g.game.external.send({
				type: "end",
				sessionId
			} as COEExternalMessage);
		}
	}
}

import type { Controller } from "../Controller";
import type { Action } from "../parameters";

interface BroadcastDataBuffer<T> {
	data: T;
	priority: number;
}

export class BaseController<Command, ActionData> implements Controller<Command, ActionData> {
	/**
	 * 本 Controller と紐づく Scene のアセット情報。
	 * `this.onLoad` の発火以降しか取得できない点に注意。
	 */
	assets: { [assetId: string]: g.Asset } = {};
	/**
	 * 本 Controller と紐づく Scene のアセットへのアクセサ。
	 */
	asset: g.AssetAccessor;
	/**
	 * 本 controller による g.MessageEvent の処理を一時的にロックするかどうか。
	 *
	 * 通常、ゲーム開発者は本値を参照・また書き換えてはならない。
	 */
	lockingProcessingMessageEvent: boolean = false;

	onLoad: g.Trigger<void> = new g.Trigger();
	onUpdate: g.Trigger<void> = new g.Trigger();
	onActionReceive: g.Trigger<Action<ActionData>> = new g.Trigger();

	/**
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onLoad` を利用すること。
	 */
	loaded: g.Trigger<void> = this.onLoad;
	/**
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onUpdate` を利用すること。
	 */
	update: g.Trigger<void> = this.onUpdate;
	/**
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onActionReceive` を利用すること。
	 */
	actionReceived: g.Trigger<Action<ActionData>> = this.onActionReceive;

	private timerManager: g.TimerManager;
	private broadcastDataBuffer: BroadcastDataBuffer<any>[] = [];

	constructor() {
		this.asset = new g.AssetAccessor(g.game._assetManager);
		this.timerManager = new g.TimerManager(this.onUpdate, g.game.fps);
	}

	/**
	 * View に対してデータをブロードキャストする。
	 * @param data プロードキャストするデータ
	 * @param priority プライオリティ。省略時は 0
	 */
	broadcast(data: Command, priority: number = 0): void {
		this.broadcastDataBuffer.push({ data, priority });
	}

	setTimeout(func: () => void, duration: number, owner?: any): g.TimerIdentifier {
		return this.timerManager.setTimeout(func, duration, owner);
	}

	setInterval(func: () => void, interval: number, owner?: any): g.TimerIdentifier {
		return this.timerManager.setInterval(func, interval, owner);
	}

	clearTimeout(id: g.TimerIdentifier): void {
		this.timerManager.clearTimeout(id);
	}

	clearInterval(id: g.TimerIdentifier): void {
		this.timerManager.clearInterval(id);
	}

	destroy(): void {
		this.onUpdate.destroy();
		this.onLoad.destroy();
		this.onActionReceive.destroy();

		this.assets = null!;
		this.asset = null!;
		this.timerManager = null!;
		this.broadcastDataBuffer = null!;
		this.onUpdate = null!;
		this.onLoad = null!;
		this.onActionReceive = null!;
		this.update = null!;
		this.loaded = null!;
		this.actionReceived = null!;
	}

	getBroadcastDataBuffer(): BroadcastDataBuffer<any>[] | null {
		if (this.broadcastDataBuffer.length) {
			return this.broadcastDataBuffer.splice(0);
		}
		return null;
	}
}

import type { COESessionStartMessage } from "@akashic-extension/coe-messages";
import { getSessionId, isTrustedAction } from "../global";
import type { Action } from "../parameters";
import { BaseController } from "./BaseController";

/**
 * coe に準拠した処理をラップしたコントローラ。
 */
export class COEController<Command, ActionData> extends BaseController<Command, ActionData> {
	/**
	 * COESessionStartMessage を信用された経路から送信された際に呼び出される trigger 。
	 */
	onStartSessionRequest: g.Trigger<COESessionStartMessage<any>> = new g.Trigger();

	/**
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onStartSessionRequest` を利用すること。
	 */
	startSessionRequested: g.Trigger<COESessionStartMessage<any>> = this.onStartSessionRequest;

	constructor() {
		super();
		this.onActionReceive.add(this.handleCOEMessageEventReceive, this);
	}

	/**
	 * 全クライアントに終了をブロードキャストする。
	 * このメソッド呼び出し後、 send プラグイン経由で `result` の値を含めた終了メッセージがシステム側に通知される。
	 *
	 * @param result 結果の値。
	 */
	broadcastEnd(result?: any): void {
		if (result != null) {
			this.broadcast({
				type: "end",
				sessionId: getSessionId(),
				result
			} as any);
		} else {
			this.broadcast({
				type: "end",
				sessionId: getSessionId()
			} as any);
		}
	}

	// override
	destroy(): void {
		this.onActionReceive.remove(this.handleCOEMessageEventReceive, this);
		this.onStartSessionRequest.destroy();
		this.onStartSessionRequest = null!;
		this.startSessionRequested = null!;
		super.destroy();
	}

	private handleCOEMessageEventReceive(action?: Action<any>): void {
		if (action && action.data && isTrustedAction(action)) {
			if (action.data.type === "start") {
				this.onStartSessionRequest.fire(action.data);
				this.lockingProcessingMessageEvent = true;
				this.onUpdate.addOnce(() => {
					this.lockingProcessingMessageEvent = false;
				});
			} else if (action.data.type === "child_start" || action.data.type === "child_end") {
				this.broadcast(action.data);
			} else if (action.data.type === "end") {
				this.broadcastEnd(action.data.sessionId);
			}
		}
	}
}

import type { COEChildSessionEndMessage, COEChildSessionStartMessage, COEEndMessage } from "@akashic-extension/coe-messages";
import { exit, exitSession, startSession } from "../global";
import { SceneWatcher } from "../SceneWatcher";

/**
 * @deprecated 後方互換
 * COEPlugin#COEExitSessionParameters を拡張したインタフェース。
 */
interface COEExtendChildSessionEndMessage extends COEChildSessionEndMessage {
	needsResult?: boolean;
	needsPlaylog?: boolean;
}

type COEMessage = COEChildSessionStartMessage | COEExtendChildSessionEndMessage | COEEndMessage;

/**
 * coe のメッセージイベントを coe-plugin へ橋渡しする EventHandler 。
 */
export class COEMessageEventHandler extends SceneWatcher {
	protected handleScene(scene: g.Scene): void {
		// 重複の防止および trigger の最後尾に handler を追加する
		scene.onMessage.remove(this.handleMessageEvent, this);
		scene.onMessage.add(this.handleMessageEvent, this);
	}

	protected handleMessageEvent(event?: g.MessageEvent): void {
		if (!event) return;
		const message = event.data as COEMessage;
		if (message.type === "child_start") {
			startSession({
				sessionId: message.parameters.sessionId,
				delayRange: message.parameters.delayRange,
				application: message.parameters.application,
				cascadeApplications: message.parameters.cascadeApplications,
				local: message.parameters.local,
				localEvents: message.parameters.localEvents,
				eventSendablePlayers: message.parameters.eventSendablePlayers,
				additionalData: message.parameters.additionalData,
				size: message.parameters.size,
				playlog: message.parameters.playlog
			});
		} else if (message.type === "child_end") {
			// NOTE: 後方互換のための処理。
			const coeParams = {
				needsResult: !!message.needsResult,
				needsPlaylog: !!message.needsPlaylog
			};
			exitSession(message.parameters.sessionId, coeParams);
		} else if (message.type === "end") {
			// NOTE: 後方互換のための処理。
			exit(message.result);
		}
	}
}

import type * as pl from "@akashic/playlog";
import type { View } from "../View";
import type { BaseController } from "./BaseController";

export interface SceneParameters<Command, ActionData> extends g.SceneParameterObject {
	local?: "interpolate-local" | "non-local";
	controller: BaseController<Command, ActionData>;
}

/**
 * コントローラにより制御される g.Scene 。
 *
 * 本シーンを利用した場合、すべての g.MessageEvent がフレームワーク側で握りつぶされる点に注意。
 * また、以下のパラメータの初期値が g.Scene と異なる点に注意。
 * * local: "interpolate-local"
 * * tickGenerationMode: "manual"
 */
export class Scene<Command, ActionData> extends g.Scene implements View<Command, ActionData> {
	onCommandReceive: g.Trigger<Command> = new g.Trigger();
	commandReceived: g.Trigger<Command> = this.onCommandReceive;
	private _generatesTickManually: boolean = false;
	private _sentInitialEvents: boolean = false;

	/**
	 * 本 Scene に紐づく Controller のインスタンス。
	 *
	 * 通常、ゲーム開発者は本値を参照してはならない。
	 * `this.send()` のみで Controller と通信を行うべきである。
	 */
	protected _controller: BaseController<Command, ActionData>;
	private handleEventFilter_bound: g.EventFilter;

	constructor(params: SceneParameters<Command, ActionData>) {
		super({
			local: "interpolate-local",
			tickGenerationMode: "manual",
			...params
		});

		this._generatesTickManually = this.tickGenerationMode === "manual";
		this._controller = params.controller;
		this.handleEventFilter_bound = this.handleEventFilter.bind(this);
		this.onMessage.add(this.handleMessageEventReceive, this);
		this.onStateChange.add(this.handleStateChange, this);

		if (g.game.isActiveInstance()) {
			this.onUpdate.add(this.fireControllerUpdate, this);
			if (this._generatesTickManually) {
				this.onUpdate.add(this.raiseTickIfMessageEventExists, this);
			}
			this.onLoad.addOnce(() => {
				this._controller.assets = this.assets;
				this._controller.onLoad.fire();
			});
		}
	}

	send(data: ActionData, priority?: number): void {
		this.game.raiseEvent(new g.MessageEvent(data, undefined, false, priority));
	}

	// override
	destroy(): void {
		this.onCommandReceive.destroy();
		this.game.removeEventFilter(this.handleEventFilter_bound);
		this.onMessage.remove(this.handleMessageEventReceive, this);

		this.onCommandReceive = null!;
		this._controller = null!;
		this.handleEventFilter_bound = null!;

		super.destroy();
	}

	private fireControllerUpdate(): void {
		this._controller.onUpdate.fire();
	}

	private handleEventFilter(pevs: pl.Event[], { processNext }: g.EventFilterController): pl.Event[] {
		const filtered: pl.Event[] = [];

		if (!this._generatesTickManually) {
			if (!this._sentInitialEvents) {
				// NOTE: 手動進行->自動進行切替時に自動進行の開始時刻が不明となってしまうため、シーンの切替時に timestamp を挿入する
				filtered.push([0x2, null!, null, Math.floor(g.game.getCurrentTime())]);
				this._sentInitialEvents = true;
			}
			const buffer = this._controller.getBroadcastDataBuffer();
			if (buffer) {
				filtered.push(...buffer.map<pl.Event>(({ data, priority }) => [0x20, priority, null, data]));
			}
		}

		for (let i = 0; i < pevs.length; i++) {
			const pev = pevs[i];
			const type = pev[0];
			const playerId = pev[2];

			if (this._controller.lockingProcessingMessageEvent) {
				processNext(pev);
				continue;
			}

			if (type === 0x20) {
				// g.MessageEvent
				// 信頼されているメッセージ (playerId === TrustedPlayerId) かどうかは、各アプリケーション実装者が判断する。
				this._controller.onActionReceive.fire({
					player: {
						id: playerId ?? undefined
					},
					data: pev[3]
				});
			} else {
				filtered.push(pev);
			}
		}

		return filtered;
	}

	private raiseTickIfMessageEventExists(): void {
		const buffer = this._controller.getBroadcastDataBuffer();
		if (!buffer) return;
		const events = buffer.map(({ data, priority }) => new g.MessageEvent(data, undefined, undefined, priority));
		const timestamp = new g.TimestampEvent(Math.floor(g.game.getCurrentTime()), null as any);
		this.game.raiseTick([timestamp, ...events]);
	}

	private handleMessageEventReceive(message?: g.MessageEvent): void {
		if (!message) return;
		this.onCommandReceive.fire(message.data);
	}

	private handleStateChange(state?: g.SceneStateString): void {
		if (state === "deactive") {
			this.game.removeEventFilter(this.handleEventFilter_bound);
		} else if (state === "active") {
			this.game.addEventFilter(this.handleEventFilter_bound, true);
			this._sentInitialEvents = false;
		}
	}
}

